1	#ifndef FABRIC_TILE_H
2	#define FABRIC_TILE_H
3	
4	/********************************************************************
5	 * Include header files required by the data structure definition
6	 *******************************************************************/
7	#include <vector>
8	
9	#include "device_grid.h"
10	#include "device_rr_gsb.h"
11	#include "fabric_tile_fwd.h"
12	#include "vtr_geometry.h"
13	#include "vtr_vector.h"
14	
15	/* namespace openfpga begins */
16	namespace openfpga {
17	
18	/********************************************************************
19	 * Object models the tiles in an FPGA fabric
20	 * This includes:
21	 * 1. a collection of tiles, each which contains a programmable block and
22	 *surrounding routing blocks
23	 * 2. a collection of unique tiles
24	 *******************************************************************/
25	class FabricTile {
26	 public: /* Accessors */
27	  vtr::Point<size_t> tile_coordinate(const FabricTileId& tile_id) const;
28	  /* Return all the root (bottom-left point) coordinates of programmable blocks
29	   * under a given tile. */
30	  std::vector<vtr::Point<size_t>> pb_coordinates(
31	    const FabricTileId& tile_id) const;
32	  std::vector<vtr::Point<size_t>> cb_coordinates(
33	    const FabricTileId& tile_id, const e_rr_type& cb_type) const;
34	  std::vector<vtr::Point<size_t>> sb_coordinates(
35	    const FabricTileId& tile_id) const;
36	  /** @brief With a given coordinate, find the id of the unique tile (which is
37	   * the same as the tile in structure) */
38	  FabricTileId unique_tile(const vtr::Point<size_t>& coord) const;
39	  /** @brief With a given tile id, find the id of its unique tile (which is
40	   * the same as the tile in structure) */
41	  FabricTileId find_unique_tile(const FabricTileId& tile_id) const;
42	  /** @brief Find the tile info with a given coordinate */
43	  FabricTileId find_tile(const vtr::Point<size_t>& coord) const;
44	  /** @brief Find the id of a tile, with a given coordinate of the programmable
45	   * block under the tile */
46	  FabricTileId find_tile_by_pb_coordinate(
47	    const vtr::Point<size_t>& coord) const;
48	  /** @brief Find the id of a tile, with a given coordinate of the connection
49	   * block under the tile */
50	  FabricTileId find_tile_by_cb_coordinate(
51	    const e_rr_type& cb_type, const vtr::Point<size_t>& coord) const;
52	  /** @brief Find the id of a tile, with a given coordinate of the switch block
53	   * under the tile */
54	  FabricTileId find_tile_by_sb_coordinate(
55	    const vtr::Point<size_t>& coord) const;
56	  /** @brief Find the coordinate of the unique tile w.r.t the tile with a tile
57	   * id */
58	  vtr::Point<size_t> unique_tile_coordinate(const FabricTileId& tile_id) const;
59	  /** @brief Return a list of unique tiles */
60	  std::vector<FabricTileId> unique_tiles() const;
61	  /** @brief Find the index of a programmable block in the internal list by a
62	   * given coordinate. Note that the coord can be either the one in device grid
63	   * or the one of gsb which the programmable block belongs to  */
64	  size_t find_pb_index_in_tile(const FabricTileId& tile_id,
65	                               const vtr::Point<size_t>& coord,
66	                               const bool& use_gsb_coord = false) const;
67	  /** @brief Find the index of a switch block in the internal list by a given
68	   * coordinate. */
69	  size_t find_sb_index_in_tile(const FabricTileId& tile_id,
70	                               const vtr::Point<size_t>& coord) const;
71	  /** @brief Find the index of a connection block in the internal list by a
72	   * given coordinate. */
73	  size_t find_cb_index_in_tile(const FabricTileId& tile_id,
74	                               const e_rr_type& cb_type,
75	                               const vtr::Point<size_t>& coord) const;
76	  /** @brief Find the coodinate of a connection block in its unique tile. For
77	   * example, a cbx[1][0] is the 2nd element of the connection block list in
78	   * tile[1][1], while the unique tile of tile[1][1] is tile[2][2]. We will find
79	   * the 2nd element of the connection block list in tile[2][2] and return its
80	   * coordinate. Error out on any exception. */
81	  vtr::Point<size_t> find_cb_coordinate_in_unique_tile(
82	    const FabricTileId& tile_id, const e_rr_type& cb_type,
83	    const vtr::Point<size_t>& cb_coord) const;
84	  /** @brief Find the coodinate of a programmable block in its unique tile. For
85	   * example, a pb[1][0] is the 2nd element of the programmable block list in
86	   * tile[1][1], while the unique tile of tile[1][1] is tile[2][2]. We will find
87	   * the 2nd element of the programmable block list in tile[2][2] and return its
88	   * coordinate. Error out on any exception. */
89	  vtr::Point<size_t> find_pb_coordinate_in_unique_tile(
90	    const FabricTileId& tile_id, const vtr::Point<size_t>& pb_coord) const;
91	  /** @brief Find the coodinate of a switch block in its unique tile. For
92	   * example, a pb[1][0] is the 2nd element of the switch block list in
93	   * tile[1][1], while the unique tile of tile[1][1] is tile[2][2]. We will find
94	   * the 2nd element of the switch block list in tile[2][2] and return its
95	   * coordinate. Error out on any exception. */
96	  vtr::Point<size_t> find_sb_coordinate_in_unique_tile(
97	    const FabricTileId& tile_id, const vtr::Point<size_t>& sb_coord) const;
98	  /** @brief Check if a programmable block (with a coordinate) exists in a tile.
99	   * Note that the coord can be either the one in device grid or the one of gsb
100	   * which the programmable block belongs to
101	   */
102	  bool pb_in_tile(const FabricTileId& tile_id, const vtr::Point<size_t>& coord,
103	                  const bool& use_gsb_coord = false) const;
104	  /** @brief Check if a switch block (with a coordinate) exists in a tile */
105	  bool sb_in_tile(const FabricTileId& tile_id,
106	                  const vtr::Point<size_t>& coord) const;
107	  /** @brief Check if a connection block (with a coordinate) exists in a tile */
108	  bool cb_in_tile(const FabricTileId& tile_id, const e_rr_type& cb_type,
109	                  const vtr::Point<size_t>& coord) const;
110	  /** @brief Identify if the fabric tile is empty: no tiles are defined */
111	  bool empty() const;
112	
113	 public: /* Mutators */
114	  FabricTileId create_tile(const vtr::Point<size_t>& coord);
115	  bool set_tile_coordinate(const FabricTileId& tile_id,
116	                           const vtr::Point<size_t>& coord);
117	  int add_pb_coordinate(const FabricTileId& tile_id,
118	                        const vtr::Point<size_t>& coord,
119	                        const vtr::Point<size_t>& gsb_coord);
120	  /* Set the top-right coordinate of a pb. This is mainly for heterogeneous
121	   * blocks, whose height or width can be > 1 */
122	  int set_pb_max_coordinate(const FabricTileId& tile_id, const size_t& pb_index,
123	                            const vtr::Point<size_t>& max_coord);
124	  int add_cb_coordinate(const FabricTileId& tile_id, const e_rr_type& cb_type,
125	                        const vtr::Point<size_t>& coord);
126	  int add_sb_coordinate(const FabricTileId& tile_id,
127	                        const vtr::Point<size_t>& coord);
128	  /** @brief Build a list of unique tiles by comparing the coordinates in
129	   * DeviceRRGSB */
130	  void build_unique_tiles();
131	  /** @brief Clear all the content */
132	  void clear();
133	  /** @brief Initialize the data with a given range. Used by constructors */
134	  void init(const vtr::Point<size_t>& max_coord);
135	  /** @brief Identify the number of unique tiles and keep in the lookup */
136	  int build_unique_tiles(const DeviceGrid& grids,
137	                         const DeviceRRGSB& device_rr_gsb, const bool& verbose);
138	
139	 public: /* Validators */
140	  bool valid_tile_id(const FabricTileId& tile_id) const;
141	
142	 private: /* Internal validators */
143	  /** @brief Identify if two tile are equivalent in their sub-modules, including
144	   * pb, cbx, cby and sb */
145	  bool equivalent_tile(const FabricTileId& tile_a, const FabricTileId& tile_b,
146	                       const DeviceGrid& grids,
147	                       const DeviceRRGSB& device_rr_gsb) const;
148	
149	 private: /* Internal builders */
150	  void invalidate_tile_in_lookup(const vtr::Point<size_t>& coord);
151	  void invalidate_pb_in_lookup(const vtr::Point<size_t>& coord);
152	  void invalidate_cbx_in_lookup(const vtr::Point<size_t>& coord);
153	  void invalidate_cby_in_lookup(const vtr::Point<size_t>& coord);
154	  void invalidate_sb_in_lookup(const vtr::Point<size_t>& coord);
155	  bool register_tile_in_lookup(const FabricTileId& tile_id,
156	                               const vtr::Point<size_t>& coord);
157	  bool register_pb_in_lookup(const FabricTileId& tile_id,
158	                             const vtr::Point<size_t>& coord);
