#pragma once

/********************************************************************
 * Include header files required by the data structure definition
 *******************************************************************/
#include <map>

/* Header from vpr library */
#include "clustered_netlist.h"
#include "physical_pb.h"

/* Begin namespace openfpga */
namespace openfpga {

/********************************************************************
 * This is the critical data structure to link the pb_type in VPR
 * to openfpga annotations
 * With a given pb_type pointer, it aims to identify:
 * 1. if the pb_type is a physical pb_type or a operating pb_type
 * 2. what is the circuit model id linked to a physical pb_type
 * 3. what is the physical pb_type for an operating pb_type
 * 4. what is the mode pointer that represents the physical mode for a pb_type
 *******************************************************************/
class VprClusteringAnnotation {
 public: /* Constructor */
  VprClusteringAnnotation();

 public: /* Public accessors */
  /* Xifan Tang: I created two functions for each data query in purpose!
   * As this is an annotation, some net/block may be changed to invalid id
   * In this case, return an invalid value does not mean that a net is not
   * renamed
   */
  bool is_net_renamed(const ClusterBlockId& block_id,
                      const int& pin_index) const;
  ClusterNetId net(const ClusterBlockId& block_id, const int& pin_index) const;
  bool is_truth_table_adapted(t_pb* pb) const;
  AtomNetlist::TruthTable truth_table(t_pb* pb) const;
  PhysicalPb physical_pb(const ClusterBlockId& block_id) const;
  t_logical_block_type_ptr physical_equivalent_site(
    const ClusterBlockId& block_id) const;

 public: /* Public mutators */
  void rename_net(const ClusterBlockId& block_id, const int& pin_index,
                  const ClusterNetId& net_id);
  void adapt_truth_table(t_pb* pb, const AtomNetlist::TruthTable& tt);
  void add_physical_pb(const ClusterBlockId& block_id,
                       const PhysicalPb& physical_pb);
  PhysicalPb& mutable_physical_pb(const ClusterBlockId& block_id);
  void set_physical_equivalent_site(const ClusterBlockId& block_id,
                                    t_logical_block_type_ptr phy_equ_site);

 public: /* Clean-up */
  void clear_net_remapping();

 private: /* Internal data */
  /* Pair a regular pb_type to its physical pb_type */
  std::map<ClusterBlockId, std::map<int, ClusterNetId>> net_names_;
  std::map<t_pb*, AtomNetlist::TruthTable> block_truth_tables_;

  /* Link clustered blocks to physical pb (mapping results) */
  std::map<ClusterBlockId, PhysicalPb> physical_pbs_;
  /* Map from cluster block to its physical equivalent site (pb_type). This is
   * due to that some cluster block can be mapped to logical equivalent site
   * during packing and then remapped to its physical equivalent site during
   * placement and routing. */
  std::map<ClusterBlockId, t_logical_block_type_ptr> phy_equ_sites_;
};

} /* End namespace openfpga*/

#ifndef VPR_PLACEMENT_ANNOTATION_H
#define VPR_PLACEMENT_ANNOTATION_H

/********************************************************************
 * Include header files required by the data structure definition
 *******************************************************************/
#include <map>

/* Header from vtrutil library */
#include "vtr_geometry.h"

/* Header from vpr library */
#include "clustered_netlist.h"
#include "device_grid.h"

/* Begin namespace openfpga */
namespace openfpga {

/********************************************************************
 * This is the critical data structure to annotate placement results
 * in VPR context
 *******************************************************************/
class VprPlacementAnnotation {
 public: /* Public accessors */
  std::vector<ClusterBlockId> grid_blocks(
    const vtr::Point<size_t>& grid_coord) const;

 public: /* Public mutators */
  void init_mapped_blocks(const DeviceGrid& grids);
  void add_mapped_block(const vtr::Point<size_t>& grid_coord, const size_t& z,
                        const ClusterBlockId& mapped_block);

 private: /* Internal data */
  /* A direct mapping show each mapped/unmapped blocks in grids
   * The blocks_ array represents each grid on the FPGA fabric
   * For example, block_[x][y] showed the mapped/unmapped blocks
   * at grid[x][y]. The third coordinate 'z' is the index of the same
   * type of blocks in the grids. This is mainly applied to I/O
   * blocks where you may have >1 I/O in a grid
   *
   * Note that this is different from the grid blocks in PlacementContext
   * VPR considers only mapped blocks while this annotation
   * considers both unmapped and mapped blocks
   * Unmapped blocks will be labelled as an invalid id in the vector
   */
  vtr::Matrix<std::vector<ClusterBlockId>> blocks_;
};

} /* End namespace openfpga*/

#endif

