1	/********************************************************************
2	 * This file includes functions to detect and correct any naming
3	 * in the users' BLIF netlist that violates the syntax of OpenFPGA
4	 * fabric generator, i.e., Verilog generator and SPICE generator
5	 *******************************************************************/
6	#include <fstream>
7	#include <string>
8	
9	/* Headers from vtrutil library */
10	#include "vtr_assert.h"
11	#include "vtr_log.h"
12	#include "vtr_time.h"
13	
14	/* Headers from openfpgashell library */
15	#include "command_exit_codes.h"
16	
17	/* Headers from archopenfpga library */
18	#include "write_xml_utils.h"
19	
20	/* Headers from openfpgautil library */
21	#include "check_netlist_naming_conflict.h"
22	#include "openfpga_digest.h"
23	
24	/* Include global variables of VPR */
25	#include "globals.h"
26	
27	/* begin namespace openfpga */
28	namespace openfpga {
29	
30	/********************************************************************
31	 * This function aims to check if the name contains any of the
32	 * sensitive characters in the list
33	 * Return a string of sensitive characters which are contained
34	 * in the name
35	 *******************************************************************/
36	static std::string name_contain_sensitive_chars(
37	  const std::string& name, const std::string& sensitive_chars) {
38	  std::string violation;
39	
40	  for (const char& sensitive_char : sensitive_chars) {
41	    /* Return true since we find a characters */
42	    if (std::string::npos != name.find(sensitive_char)) {
43	      violation.push_back(sensitive_char);
44	    }
45	  }
46	
47	  return violation;
48	}
49	
50	/********************************************************************
51	 * This function aims to fix up a name that contains any of the
52	 * sensitive characters in the list
53	 * Return a string the fixed name
54	 *******************************************************************/
55	static std::string fix_name_contain_sensitive_chars(
56	  const std::string& name, const std::string& sensitive_chars,
57	  const std::string& fix_chars) {
58	  std::string fixed_name = name;
59	
60	  VTR_ASSERT(sensitive_chars.length() == fix_chars.length());
61	
62	  for (size_t ichar = 0; ichar < sensitive_chars.length(); ++ichar) {
63	    /* Keep fixing the characters until we cannot find anymore */
64	    std::string::size_type pos = 0u;
65	    while (std::string::npos !=
66	           (pos = fixed_name.find(sensitive_chars[ichar], pos))) {
67	      fixed_name.replace(pos, 1, std::string(1, fix_chars[ichar]));
68	      pos += 1;
69	    }
70	  }
71	
72	  return fixed_name;
73	}
74	
75	/********************************************************************
76	 * Detect and report any naming conflict by checking a list of
77	 * sensitive characters
78	 * - Iterate over all the blocks and see if any block name contain
79	 *   any sensitive character
